import React from 'react';
import { GraduationCap, Home, BookOpen, PenTool, FileText, BarChart3, Menu, X } from 'lucide-react';

export default function Sidebar({ currentPage, setCurrentPage, isOpen, setIsOpen, selectedLevel, setSelectedLevel, LEVELS }) {
  const navItems = [
    { id: 'home', label: 'ホーム', icon: Home },
    { id: 'textbook', label: '教科書', icon: BookOpen },
    { id: 'practice', label: '問題演習', icon: PenTool },
    { id: 'exam', label: '模擬試験', icon: FileText },
    { id: 'progress', label: '学習進捗', icon: BarChart3 },
  ];

  const handleNavClick = (pageId) => {
    setCurrentPage(pageId);
    if (window.innerWidth < 1024) {
      setIsOpen(false);
    }
  };

  return (
    <>
      {/* Mobile menu button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="fixed top-4 left-4 lg:hidden z-50 p-2 rounded-lg bg-white shadow-md hover:bg-gray-50"
      >
        {isOpen ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Mobile overlay */}
      {isOpen && (
        <div
          className="fixed inset-0 bg-black/50 lg:hidden z-30"
          onClick={() => setIsOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside
        className={`fixed lg:static inset-y-0 left-0 w-72 bg-gradient-to-b from-slate-900 to-slate-800 text-white z-40 transform transition-transform duration-300 lg:translate-x-0 ${
          isOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
      >
        {/* Logo Section */}
        <div className="p-6 border-b border-slate-700">
          <div className="flex items-center gap-3 mb-2">
            <div className="bg-blue-500 p-2 rounded-lg">
              <GraduationCap size={28} className="text-white" />
            </div>
            <div>
              <h1 className="font-bold text-lg">統計検定道場</h1>
              <p className="text-xs text-slate-300">Statistical Learning Hub</p>
            </div>
          </div>
        </div>

        {/* Level Selector */}
        <div className="p-6 border-b border-slate-700">
          <p className="text-xs font-semibold text-slate-300 uppercase mb-3">難易度を選択</p>
          <div className="space-y-2">
            {LEVELS.map((level) => (
              <button
                key={level.id}
                onClick={() => setSelectedLevel(level.id)}
                className={`w-full px-4 py-3 rounded-lg font-semibold text-sm transition-all ${
                  selectedLevel === level.id
                    ? `${level.bgColor} text-white shadow-lg scale-105`
                    : `bg-slate-700 text-slate-200 hover:bg-slate-600`
                }`}
              >
                {level.name}
              </button>
            ))}
          </div>
        </div>

        {/* Navigation Items */}
        <nav className="p-6 space-y-2">
          {navItems.map((item) => {
            const Icon = item.icon;
            return (
              <button
                key={item.id}
                onClick={() => handleNavClick(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
                  currentPage === item.id
                    ? 'bg-blue-500 text-white shadow-lg'
                    : 'text-slate-300 hover:bg-slate-700/50 hover:text-white'
                }`}
              >
                <Icon size={20} />
                <span className="font-medium">{item.label}</span>
              </button>
            );
          })}
        </nav>

        {/* Footer */}
        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-700 text-xs text-slate-400 text-center">
          <p>© 2026 統計検定道場</p>
        </div>
      </aside>
    </>
  );
}

import React from 'react';
import { BookOpen, PenTool, FileText, BarChart3, TrendingUp, Calendar, Flame } from 'lucide-react';

export default function HomePage({ setCurrentPage, selectedLevel, stats, LEVELS, topicCount, questionCount }) {
  const level = LEVELS.find(l => l.id === selectedLevel);

  const statCards = [
    { label: 'カテゴリ数', value: topicCount, icon: BookOpen, color: 'bg-blue-500' },
    { label: '問題数', value: questionCount, icon: PenTool, color: 'bg-purple-500' },
    { label: '回答済み', value: stats.totalAnswered || 0, icon: TrendingUp, color: 'bg-green-500' },
  ];

  const quickNavCards = [
    { id: 'textbook', label: '教科書', icon: BookOpen, color: 'from-blue-500 to-blue-600', description: '統計学の基礎を学ぶ' },
    { id: 'practice', label: '問題演習', icon: PenTool, color: 'from-purple-500 to-purple-600', description: '問題を解いて復習' },
    { id: 'exam', label: '模擬試験', icon: FileText, color: 'from-orange-500 to-orange-600', description: '本番環境で模試' },
    { id: 'progress', label: '学習進捗', icon: BarChart3, color: 'from-green-500 to-green-600', description: '成績を確認' },
  ];

  const hasProgress = stats.totalAnswered > 0;

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 pt-20 lg:pt-0">
      {/* Hero Banner */}
      <div className={`bg-gradient-to-r ${level?.bgGradient || 'from-blue-600 to-blue-700'} text-white py-12 px-6 lg:px-12`}>
        <div className="max-w-4xl mx-auto">
          <h1 className="text-4xl lg:text-5xl font-bold mb-3">
            {level?.name}へようこそ！
          </h1>
          <p className="text-lg opacity-90">
            統計検定合格に向けて、効率的に学習を進めましょう
          </p>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-6 lg:px-12 py-12">
        {/* Stat Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-12">
          {statCards.map((card, idx) => {
            const Icon = card.icon;
            return (
              <div key={idx} className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition-shadow">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-slate-600 text-sm font-medium">{card.label}</p>
                    <p className="text-3xl font-bold text-slate-900 mt-2">{card.value}</p>
                  </div>
                  <div className={`${card.color} p-3 rounded-lg`}>
                    <Icon size={28} className="text-white" />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Progress Overview - Show if has answered questions */}
        {hasProgress && (
          <div className="bg-white rounded-lg shadow-lg p-8 mb-12 border-l-4 border-blue-500">
            <h2 className="text-2xl font-bold text-slate-900 mb-6">学習状況</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div>
                <div className="flex items-center gap-2 mb-2">
                  <TrendingUp size={20} className="text-blue-500" />
                  <p className="text-slate-600 font-medium">正答率</p>
                </div>
                <p className="text-3xl font-bold text-slate-900">
                  {stats.totalAnswered > 0
                    ? ((stats.totalCorrect / stats.totalAnswered) * 100).toFixed(1)
                    : 0}%
                </p>
              </div>
              <div>
                <div className="flex items-center gap-2 mb-2">
                  <Calendar size={20} className="text-purple-500" />
                  <p className="text-slate-600 font-medium">学習日数</p>
                </div>
                <p className="text-3xl font-bold text-slate-900">
                  {stats.studyDays || 0}日
                </p>
              </div>
              <div>
                <div className="flex items-center gap-2 mb-2">
                  <Flame size={20} className="text-orange-500" />
                  <p className="text-slate-600 font-medium">連続学習</p>
                </div>
                <p className="text-3xl font-bold text-slate-900">
                  {stats.streak || 0}日
                </p>
              </div>
            </div>
          </div>
        )}

        {/* Quick Navigation Cards */}
        <div>
          <h2 className="text-2xl font-bold text-slate-900 mb-6">次のステップ</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {quickNavCards.map((card) => {
              const Icon = card.icon;
              return (
                <button
                  key={card.id}
                  onClick={() => setCurrentPage(card.id)}
                  className="bg-gradient-to-br from-white to-slate-50 border border-slate-200 rounded-lg p-6 hover:shadow-lg transition-all hover:scale-105 text-left group"
                >
                  <div className={`bg-gradient-to-r ${card.color} p-3 rounded-lg w-fit mb-4 group-hover:scale-110 transition-transform`}>
                    <Icon size={28} className="text-white" />
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-1">{card.label}</h3>
                  <p className="text-slate-600">{card.description}</p>
                </button>
              );
            })}
          </div>
        </div>

        {/* Encouragement Message */}
        {!hasProgress && (
          <div className="mt-12 bg-gradient-to-r from-blue-50 to-purple-50 border border-blue-200 rounded-lg p-8 text-center">
            <p className="text-lg text-slate-700">
              さあ、学習を始めましょう！まずは<span className="font-bold">教科書</span>で基礎を学ぶか、
              <span className="font-bold">問題演習</span>に挑戦してください。
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { ArrowLeft, ChevronLeft, ChevronRight } from 'lucide-react';

export default function TextbookPage({ selectedLevel, topics, LEVELS }) {
  const [selectedTopic, setSelectedTopic] = useState(null);
  const [selectedSection, setSelectedSection] = useState(0);
  const level = LEVELS.find(l => l.id === selectedLevel);

  const renderContent = (text) => {
    if (!text) return null;

    const lines = text.split('\n');
    const elements = [];
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];

      // Empty line - add spacing
      if (line.trim() === '') {
        elements.push(<div key={`empty-${i}`} className="h-2" />);
        i++;
        continue;
      }

      // Bold text (starts with **)
      if (line.startsWith('**') && line.endsWith('**')) {
        const text = line.slice(2, -2);
        elements.push(
          <h4 key={`heading-${i}`} className="text-lg font-bold text-slate-900 mt-4 mb-3">
            {text}
          </h4>
        );
        i++;
        continue;
      }

      // Bullet points (starts with -)
      if (line.trim().startsWith('- ')) {
        const bulletItems = [];
        while (i < lines.length && lines[i].trim().startsWith('- ')) {
          bulletItems.push(lines[i].trim().slice(2));
          i++;
        }
        elements.push(
          <ul key={`bullets-${i}`} className="list-disc list-inside space-y-2 text-slate-700 ml-4 mb-4">
            {bulletItems.map((item, idx) => (
              <li key={idx}>{item}</li>
            ))}
          </ul>
        );
        continue;
      }

      // Formula blocks (starts with two spaces)
      if (line.startsWith('  ') && !line.startsWith('   ')) {
        const formulas = [];
        while (i < lines.length && lines[i].startsWith('  ') && !lines[i].startsWith('   ')) {
          formulas.push(lines[i].trim());
          i++;
        }
        elements.push(
          <div key={`formula-${i}`} className="bg-slate-100 border border-slate-300 rounded-lg p-4 my-4 font-mono text-sm">
            {formulas.map((formula, idx) => (
              <div key={idx} className="text-slate-800">{formula}</div>
            ))}
          </div>
        );
        continue;
      }

      // Regular paragraph
      elements.push(
        <p key={`para-${i}`} className="text-slate-700 leading-relaxed mb-3">
          {line}
        </p>
      );
      i++;
    }

    return elements;
  };

  // Show topic list view
  if (selectedTopic === null) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 pt-20 lg:pt-0">
        <div className="max-w-4xl mx-auto px-6 lg:px-12 py-12">
          <h1 className="text-4xl font-bold text-slate-900 mb-2">教科書</h1>
          <p className="text-slate-600 mb-8">各単元の講義を確認します</p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {topics.map((topic) => (
              <button
                key={topic.id}
                onClick={() => {
                  setSelectedTopic(topic.id);
                  setSelectedSection(0);
                }}
                className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition-all hover:scale-105 text-left border border-slate-200"
              >
                <div className="flex items-start gap-4 mb-4">
                  <div className={`${level?.bgColor || 'bg-blue-500'} p-3 rounded-lg text-white`}>
                    <topic.icon size={28} />
                  </div>
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-slate-900">{topic.name}</h3>
                    <p className="text-slate-600 text-sm mt-1">
                      {topic.sections?.length || 0} セクション
                    </p>
                  </div>
                </div>
                <p className="text-slate-600 text-sm">{topic.description}</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  // Show topic detail view
  const topic = topics.find(t => t.id === selectedTopic);
  const sections = topic?.sections || [];
  const currentSection = sections[selectedSection] || {};

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 pt-20 lg:pt-0">
      <div className="max-w-4xl mx-auto px-6 lg:px-12 py-12">
        {/* Back Button */}
        <button
          onClick={() => setSelectedTopic(null)}
          className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-medium mb-6"
        >
          <ArrowLeft size={20} />
          教科書に戻る
        </button>

        {/* Topic Header */}
        <div className="bg-white rounded-lg shadow p-6 mb-8 border-l-4 border-blue-500">
          <div className="flex items-center gap-4 mb-4">
            <div className={`${level?.bgColor || 'bg-blue-500'} p-3 rounded-lg text-white`}>
              <topic.icon size={32} />
            </div>
            <div>
              <h1 className="text-3xl font-bold text-slate-900">{topic.name}</h1>
              <p className="text-slate-600 mt-1">{sections.length} セクション</p>
            </div>
          </div>
        </div>

        {/* Section Tabs */}
        {sections.length > 0 && (
          <div className="bg-white rounded-lg shadow mb-8 overflow-hidden">
            <div className="flex overflow-x-auto border-b border-slate-200">
              {sections.map((section, idx) => (
                <button
                  key={idx}
                  onClick={() => setSelectedSection(idx)}
                  className={`px-4 py-3 font-medium text-sm whitespace-nowrap transition-colors ${
                    selectedSection === idx
                      ? 'border-b-2 border-blue-500 text-blue-600 bg-blue-50'
                      : 'text-slate-600 hover:text-slate-900 hover:bg-slate-50'
                  }`}
                >
                  {section.title || `セクション ${idx + 1}`}
                </button>
              ))}
            </div>

            {/* Content Area */}
            <div className="p-8">
              <h2 className="text-2xl font-bold text-slate-900 mb-6">
                {currentSection.title || `セクション ${selectedSection + 1}`}
              </h2>

              <div className="prose prose-sm max-w-none">
                {renderContent(currentSection.content)}
              </div>

              {/* Special note for jun1kyu */}
              {selectedLevel === 'jun1kyu' && (
                <div className="mt-8 p-4 bg-blue-50 border border-blue-200 rounded-lg text-sm text-blue-800">
                  <strong>注：</strong> このカテゴリはとけたろう準1級講座の単元構成に基づいています。
                </div>
              )}
            </div>
          </div>
        )}

        {/* Navigation Buttons */}
        {sections.length > 0 && (
          <div className="flex gap-4 justify-between">
            <button
              onClick={() => setSelectedSection(Math.max(0, selectedSection - 1))}
              disabled={selectedSection === 0}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 rounded-lg font-medium text-slate-700 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50"
            >
              <ChevronLeft size={20} />
              前へ
            </button>

            <div className="flex items-center gap-2 text-slate-600 font-medium">
              {selectedSection + 1} / {sections.length}
            </div>

            <button
              onClick={() => setSelectedSection(Math.min(sections.length - 1, selectedSection + 1))}
              disabled={selectedSection === sections.length - 1}
              className="flex items-center gap-2 px-4 py-2 bg-blue-500 border border-blue-600 rounded-lg font-medium text-white disabled:opacity-50 disabled:cursor-not-allowed hover:bg-blue-600"
            >
              次へ
              <ChevronRight size={20} />
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { ChevronDown, Check, X, ChevronRight, MessageCircle } from 'lucide-react';

export default function PracticePage({ selectedLevel, questions, topics, addResult }) {
  const [selectedTopic, setSelectedTopic] = useState('all');
  const [currentQuestionIdx, setCurrentQuestionIdx] = useState(0);
  const [userAnswer, setUserAnswer] = useState(null);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [showExplanation, setShowExplanation] = useState(false);
  const [writtenAnswer, setWrittenAnswer] = useState('');

  // Filter questions by topic
  const filteredQuestions = selectedTopic === 'all'
    ? questions
    : questions.filter(q => q.topicId === selectedTopic);

  if (filteredQuestions.length === 0) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 pt-20 lg:pt-0 flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-slate-600 mb-4">このレベルではまだ問題がありません</p>
        </div>
      </div>
    );
  }

  const currentQuestion = filteredQuestions[currentQuestionIdx];
  const isChoiceQuestion = currentQuestion.type === 'choice';
  const isCorrect = currentQuestion.correctAnswer === userAnswer;

  const handleSubmit = () => {
    if (isChoiceQuestion) {
      if (userAnswer === null) return;
      setIsSubmitted(true);
      addResult({
        questionId: currentQuestion.id,
        isCorrect,
        answered: new Date(),
      });
    } else {
      // Written answer
      if (!writtenAnswer.trim()) return;
      setIsSubmitted(true);
      addResult({
        questionId: currentQuestion.id,
        isCorrect: true, // In real app, would need grading
        answered: new Date(),
      });
    }
  };

  const handleNext = () => {
    setUserAnswer(null);
    setWrittenAnswer('');
    setIsSubmitted(false);
    setShowExplanation(false);
    setCurrentQuestionIdx(Math.min(currentQuestionIdx + 1, filteredQuestions.length - 1));
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 pt-20 lg:pt-0">
      <div className="max-w-4xl mx-auto px-6 lg:px-12 py-12">
        <h1 className="text-4xl font-bold text-slate-900 mb-8">問題演習</h1>

        {/* Topic Filter Dropdown */}
        <div className="mb-8">
          <label className="block text-sm font-medium text-slate-700 mb-3">
            カテゴリで絞り込む
          </label>
          <div className="relative">
            <select
              value={selectedTopic}
              onChange={(e) => {
                setSelectedTopic(e.target.value);
                setCurrentQuestionIdx(0);
                setUserAnswer(null);
                setWrittenAnswer('');
                setIsSubmitted(false);
              }}
              className="w-full px-4 py-3 rounded-lg border border-slate-300 bg-white text-slate-900 appearance-none cursor-pointer hover:border-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">すべてのカテゴリ ({questions.length} 問)</option>
              {topics.map(topic => {
                const count = questions.filter(q => q.topicId === topic.id).length;
                return (
                  <option key={topic.id} value={topic.id}>
                    {topic.name} ({count} 問)
                  </option>
                );
              })}
            </select>
            <ChevronDown size={20} className="absolute right-3 top-3.5 text-slate-600 pointer-events-none" />
          </div>
        </div>

        {/* Question Card */}
        <div className="bg-white rounded-lg shadow-lg p-8 mb-8">
          {/* Header */}
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-4">
              <span className="inline-block bg-slate-200 text-slate-700 px-3 py-1 rounded-full text-sm font-medium">
                {isChoiceQuestion ? '選択式' : '記述式'}
              </span>
              <span className="text-slate-600 text-sm">
                {currentQuestionIdx + 1} / {filteredQuestions.length}
              </span>
            </div>
          </div>

          {/* Question Text */}
          <h2 className="text-2xl font-bold text-slate-900 mb-8 leading-relaxed">
            {currentQuestion.question}
          </h2>

          {/* Choice Question Options */}
          {isChoiceQuestion && (
            <div className="space-y-3 mb-8">
              {['A', 'B', 'C', 'D'].map((option) => {
                const optionText = currentQuestion[`option${option}`];
                const isSelected = userAnswer === option;
                const isCorrectOption = currentQuestion.correctAnswer === option;

                let buttonClass = 'bg-white border-2 border-slate-300 text-slate-900 hover:border-slate-400';

                if (isSubmitted) {
                  if (isCorrectOption) {
                    buttonClass = 'bg-green-50 border-2 border-green-500 text-slate-900';
                  } else if (isSelected && !isCorrectOption) {
                    buttonClass = 'bg-red-50 border-2 border-red-500 text-slate-900';
                  } else {
                    buttonClass = 'bg-white border-2 border-slate-300 text-slate-900';
                  }
                } else if (isSelected) {
                  buttonClass = 'bg-blue-50 border-2 border-blue-500 text-slate-900';
                }

                return (
                  <button
                    key={option}
                    onClick={() => !isSubmitted && setUserAnswer(option)}
                    disabled={isSubmitted}
                    className={`w-full p-4 rounded-lg font-medium text-left transition-all ${buttonClass} disabled:cursor-default`}
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-8 h-8 rounded-full border-2 flex items-center justify-center font-bold">
                        {option}
                      </div>
                      <span>{optionText}</span>
                      {isSubmitted && isCorrectOption && <Check className="ml-auto text-green-600" size={24} />}
                      {isSubmitted && isSelected && !isCorrectOption && <X className="ml-auto text-red-600" size={24} />}
                    </div>
                  </button>
                );
              })}
            </div>
          )}

          {/* Written Question Answer */}
          {!isChoiceQuestion && (
            <div className="mb-8">
              <textarea
                value={writtenAnswer}
                onChange={(e) => setWrittenAnswer(e.target.value)}
                disabled={isSubmitted}
                placeholder="ここに答えを入力してください..."
                className="w-full p-4 rounded-lg border border-slate-300 text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-50"
                rows={6}
              />
              {isSubmitted && (
                <div className="mt-4 p-4 bg-slate-50 rounded-lg border border-slate-200">
                  <p className="text-sm font-medium text-slate-700 mb-2">実例答案:</p>
